import React from'react';import{Outlet,useLocation}from'react-router-dom';import Sidebar from'../components/shared/Sidebar';import Header from'../components/shared/Header';
const M={'/employee':{t:'My Dashboard',s:'Your workspace'},'/employee/profile':{t:'My Profile',s:'View and update details'},'/employee/attendance':{t:'My Attendance',s:'Monthly attendance records'},'/employee/leaves':{t:'My Leaves',s:'Apply and track leaves'},'/employee/payroll':{t:'My Payroll',s:'View salary and download slips'}};
const css=`.layout{display:flex;min-height:100vh;}.lm{margin-left:var(--sw);flex:1;display:flex;flex-direction:column;min-height:100vh;min-width:0;}.lb{padding:28px;flex:1;}`;
export default function EmployeeLayout(){const{pathname}=useLocation();const m=M[pathname]||{t:'Employee',s:''};return(<><style>{css}</style><div className="layout"><Sidebar role="EMPLOYEE"/><div className="lm"><Header title={m.t} subtitle={m.s}/><main className="lb"><Outlet/></main></div></div></>);}
